// Extract Invoice/Update events from QBO webhook payload. Filters to invoice updates
// only; other entities and operations are ignored. Empty result is normal (webhook fired
// for a non-invoice change) — Split In Batches' done output handles that path cleanly.
try {
  const body = $input.first().json.body ?? $input.first().json;
  const notifications = body?.eventNotifications ?? [];
  if (!Array.isArray(notifications)) {
    throw new Error('eventNotifications is not an array');
  }
  const out = [];
  for (const n of notifications) {
    const entities = n?.dataChangeEvent?.entities ?? [];
    for (const e of entities) {
      if (e?.name === 'Invoice' && e?.operation === 'Update') {
        out.push({
          json: {
            id: String(e.id),
            realmId: String(n.realmId ?? ''),
            lastUpdated: e.lastUpdated ?? null
          }
        });
      }
    }
  }
  return out;
} catch (err) {
  throw new Error('Extract invoice updates failed: ' + err.message);
}

// Fold N rows from UPDATE...RETURNING into one item with the Slack message pre-built.
// When 0 rows were resolved (no ACTIVE sequence existed), emit rows_resolved=0 so the
// downstream IF can short-circuit silently per the spec.
// contact_name may be NULL (untagged customer) — fall back to 'customer ' + contact_id.
try {
  const items = $input.all() ?? [];
  const real = items.filter(it => it?.json && it.json.id !== undefined && it.json.id !== null);

  if (real.length === 0) {
    return [{ json: { rows_resolved: 0 } }];
  }

  const first = real[0].json;
  const invoiceJson = $('Fetch Invoice from QBO').first().json.Invoice;
  const reminderCount = real.filter(r => String(r.json.action_taken || '').startsWith('REMINDER_')).length;
  const escalated = real.some(r => r.json.action_taken === 'ESCALATED');
  const contactName = first.contact_name || ('customer ' + first.contact_id);
  const currency = first.currency_code || (invoiceJson?.CurrencyRef && invoiceJson.CurrencyRef.value) || 'USD';
  const invoiceNumber = first.invoice_number || invoiceJson?.DocNumber || invoiceJson?.Id;
  const invoicePaidAmt = '$' + Number(invoiceJson?.TotalAmt ?? 0).toFixed(2);

  const lines = [];
  lines.push(':white_check_mark: Payment received — dunning cancelled');
  lines.push('Customer: ' + contactName);
  lines.push('Invoice: #' + invoiceNumber + ' (paid ' + invoicePaidAmt + ' ' + currency + ')');
  if (reminderCount > 0) lines.push('Reminders sent before payment: ' + reminderCount);
  if (escalated) lines.push('Sequence had escalated to owner.');
  lines.push('Audit rows resolved: ' + real.length);

  return [{
    json: {
      rows_resolved: real.length,
      invoice_id: String(invoiceJson?.Id),
      invoice_number: invoiceNumber,
      contact_id: first.contact_id,
      contact_name: contactName,
      reminder_count: reminderCount,
      escalated: escalated,
      slack_text: lines.join('\n')
    }
  }];
} catch (err) {
  throw new Error('Aggregate resolved rows failed: ' + err.message);
}
